package com.example.api.service;

import com.example.api.exception.InvalidItemException;
import com.example.api.exception.ItemNotFoundException;
import com.example.api.model.Item;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.stereotype.Service;

import java.time.LocalDateTime;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.atomic.AtomicLong;

@Service
public class ItemService {

    private static final Logger logger = LoggerFactory.getLogger(ItemService.class);

    private final Map<Long, Item> itemStore = new ConcurrentHashMap<>();
    private final AtomicLong idGenerator = new AtomicLong(1);

    public ItemService() {
        logger.info("ItemService initialized with empty store");
    }

    public List<Item> getAllItems() {
        logger.info("Retrieving all items from store");
        List<Item> items = new ArrayList<>(itemStore.values());
        logger.info("Retrieved {} items from store", items.size());
        return items;
    }

    public Item getItemById(Long id) {
        logger.info("Retrieving item with id={}", id);
        Item item = itemStore.get(id);
        if (item == null) {
            logger.warn("Item not found with id={}", id);
            throw new ItemNotFoundException(id);
        }
        logger.info("Successfully retrieved item with id={}, name='{}'", id, item.getName());
        return item;
    }

    public Item createItem(Item item) {
        logger.info("Creating new item with name='{}'", item.getName());

        if (item.getName() == null || item.getName().trim().isEmpty()) {
            logger.error("Attempted to create item with null or empty name");
            throw new InvalidItemException("Item name cannot be null or empty");
        }

        if (item.getName().length() > 255) {
            logger.error("Attempted to create item with name exceeding 255 characters, length={}", item.getName().length());
            throw new InvalidItemException("Item name cannot exceed 255 characters");
        }

        Long newId = idGenerator.getAndIncrement();
        item.setId(newId);
        item.setCreatedAt(LocalDateTime.now());
        item.setUpdatedAt(LocalDateTime.now());
        itemStore.put(newId, item);

        logger.info("Successfully created item with id={}, name='{}'", newId, item.getName());
        return item;
    }

    public Item updateItem(Long id, Item updatedItem) {
        logger.info("Updating item with id={}", id);

        Item existingItem = itemStore.get(id);
        if (existingItem == null) {
            logger.warn("Cannot update item: item not found with id={}", id);
            throw new ItemNotFoundException(id);
        }

        if (updatedItem.getName() == null || updatedItem.getName().trim().isEmpty()) {
            logger.error("Attempted to update item id={} with null or empty name", id);
            throw new InvalidItemException("Item name cannot be null or empty");
        }

        if (updatedItem.getName().length() > 255) {
            logger.error("Attempted to update item id={} with name exceeding 255 characters, length={}", id, updatedItem.getName().length());
            throw new InvalidItemException("Item name cannot exceed 255 characters");
        }

        String oldName = existingItem.getName();
        existingItem.setName(updatedItem.getName());
        existingItem.setDescription(updatedItem.getDescription());
        existingItem.setUpdatedAt(LocalDateTime.now());

        logger.info("Successfully updated item id={}, name changed from '{}' to '{}'", id, oldName, updatedItem.getName());
        return existingItem;
    }

    public void deleteItem(Long id) {
        logger.info("Deleting item with id={}", id);

        Item removedItem = itemStore.remove(id);
        if (removedItem == null) {
            logger.warn("Cannot delete item: item not found with id={}", id);
            throw new ItemNotFoundException(id);
        }

        logger.info("Successfully deleted item with id={}, name='{}'", id, removedItem.getName());
    }
}

// ==================== Controller ====================

package com.example.api.controller;

import com.example.api.model.Item;
import com.example.api.service.ItemService;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

import jakarta.servlet.http.HttpServletRequest;
import java.util.List;

@RestController
@RequestMapping("/api/items")
public class ItemController {

    private static final Logger logger = LoggerFactory.getLogger(ItemController.class);

    private final ItemService itemService;

    public ItemController(ItemService itemService) {
        this.itemService = itemService;
        logger.info("ItemController initialized");
    }

    @GetMapping
    public ResponseEntity<List<Item>> getAllItems(HttpServletRequest request) {
        String clientIp = getClientIp(request);
        String userAgent = request.getHeader("User-Agent");
        logger.info("GET /api/items - Request from IP={}, User-Agent='{}'", clientIp, userAgent);

        List<Item> items = itemService.getAllItems();

        logger.info("GET /api/items - Returning {} items, status=200, IP={}", items.size(), clientIp);
        return ResponseEntity.ok(items);
    }

    @GetMapping("/{id}")
    public ResponseEntity<Item> getItemById(@PathVariable Long id, HttpServletRequest request) {
        String clientIp = getClientIp(request);
        logger.info("GET /api/items/{} - Request from IP={}", id, clientIp);

        Item item = itemService.getItemById(id);

        logger.info("GET /api/items/{} - Successfully retrieved item, status=200, IP={}", id, clientIp);
        return ResponseEntity.ok(item);
    }

    @PostMapping
    public ResponseEntity<Item> createItem(@RequestBody Item item, HttpServletRequest request) {
        String clientIp = getClientIp(request);
        logger.info("POST /api/items - Request from IP={}, item name='{}'", clientIp, item.getName());

        Item createdItem = itemService.createItem(item);

        logger.info("POST /api/items - Successfully created item id={}, status=201, IP={}", createdItem.getId(), clientIp);
        return ResponseEntity.status(HttpStatus.CREATED).body(createdItem);
    }

    @PutMapping("/{id}")
    public ResponseEntity<Item> updateItem(@PathVariable Long id, @RequestBody Item item, HttpServletRequest request) {
        String clientIp = getClientIp(request);
        logger.info("PUT /api/items/{} - Request from IP={}, new name='{}'", id, clientIp, item.getName());

        Item updatedItem = itemService.updateItem(id, item);

        logger.info("PUT /api/items/{} - Successfully updated item, status=200, IP={}", id, clientIp);
        return ResponseEntity.ok(updatedItem);
    }

    @DeleteMapping("/{id}")
    public ResponseEntity<Void> deleteItem(@PathVariable Long id, HttpServletRequest request) {
        String clientIp = getClientIp(request);
        logger.info("DELETE /api/items/{} - Request from IP={}", id, clientIp);

        itemService.deleteItem(id);

        logger.info("DELETE /api/items/{} - Successfully deleted item, status=204, IP={}", id, clientIp);
        return ResponseEntity.noContent().build();
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        String xRealIp = request.getHeader("X-Real-IP");
        if (xRealIp != null && !xRealIp.isEmpty()) {
            return xRealIp;
        }
        return request.getRemoteAddr();
    }
}

// ==================== Global Exception Handler ====================

package com.example.api.exception;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.http.converter.HttpMessageNotReadableException;
import org.springframework.web.bind.annotation.ExceptionHandler;
import org.springframework.web.bind.annotation.RestControllerAdvice;
import org.springframework.web.method.annotation.MethodArgumentTypeMismatchException;
import org.springframework.web.servlet.NoHandlerFoundException;

import jakarta.servlet.http.HttpServletRequest;
import java.time.LocalDateTime;
import java.util.LinkedHashMap;
import java.util.Map;

@RestControllerAdvice
public class GlobalExceptionHandler {

    private static final Logger logger = LoggerFactory.getLogger(GlobalExceptionHandler.class);

    @ExceptionHandler(ItemNotFoundException.class)
    public ResponseEntity<Map<String, Object>> handleItemNotFound(ItemNotFoundException ex, HttpServletRequest request) {
        String clientIp = getClientIp(request);
        logger.warn("ItemNotFoundException: {} - URI={}, Method={}, IP={}",
                ex.getMessage(), request.getRequestURI(), request.getMethod(), clientIp);

        Map<String, Object> body = buildErrorResponse(HttpStatus.NOT_FOUND, ex.getMessage(), request.getRequestURI());
        return ResponseEntity.status(HttpStatus.NOT_FOUND).body(body);
    }

    @ExceptionHandler(InvalidItemException.class)
    public ResponseEntity<Map<String, Object>> handleInvalidItem(InvalidItemException ex, HttpServletRequest request) {
        String clientIp = getClientIp(request);
        logger.warn("InvalidItemException: {} - URI={}, Method={}, IP={}",
                ex.getMessage(), request.getRequestURI(), request.getMethod(), clientIp);

        Map<String, Object> body = buildErrorResponse(HttpStatus.BAD_REQUEST, ex.getMessage(), request.getRequestURI());
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(body);
    }

    @ExceptionHandler(HttpMessageNotReadableException.class)
    public ResponseEntity<Map<String, Object>> handleHttpMessageNotReadable(HttpMessageNotReadableException ex, HttpServletRequest request) {
        String clientIp = getClientIp(request);
        logger.warn("HttpMessageNotReadableException: Malformed request body - URI={}, Method={}, IP={}",
                request.getRequestURI(), request.getMethod(), clientIp);

        Map<String, Object> body = buildErrorResponse(HttpStatus.BAD_REQUEST, "Malformed request body", request.getRequestURI());
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(body);
    }

    @ExceptionHandler(MethodArgumentTypeMismatchException.class)
    public ResponseEntity<Map<String, Object>> handleTypeMismatch(MethodArgumentTypeMismatchException ex, HttpServletRequest request) {
        String clientIp = getClientIp(request);
        logger.warn("MethodArgumentTypeMismatchException: Invalid parameter '{}' with value '{}' - URI={}, IP={}",
                ex.getName(), ex.getValue(), request.getRequestURI(), clientIp);

        String message = String.format("Invalid value '%s' for parameter '%s'", ex.getValue(), ex.getName());
        Map<String, Object> body = buildErrorResponse(HttpStatus.BAD_REQUEST, message, request.getRequestURI());
        return ResponseEntity.status(HttpStatus.BAD_REQUEST).body(body);
    }

    @ExceptionHandler(Exception.class)
    public ResponseEntity<Map<String, Object>> handleGenericException(Exception ex, HttpServletRequest request) {
        String clientIp = getClientIp(request);
        logger.error("Unhandled exception: {} - URI={}, Method={}, IP={}", 
                ex.getMessage(), request.getRequestURI(), request.getMethod(), clientIp, ex);

        Map<String, Object> body = buildErrorResponse(HttpStatus.INTERNAL_SERVER_ERROR, "An internal server error occurred", request.getRequestURI());
        return ResponseEntity.status(HttpStatus.INTERNAL_SERVER_ERROR).body(body);
    }

    private Map<String, Object> buildErrorResponse(HttpStatus status, String message, String path) {
        Map<String, Object> body = new LinkedHashMap<>();
        body.put("timestamp", LocalDateTime.now().toString());
        body.put("status", status.value());
        body.put("error", status.getReasonPhrase());
        body.put("message", message);
        body.put("path", path);
        return body;
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        String xRealIp = request.getHeader("X-Real-IP");
        if (xRealIp != null && !xRealIp.isEmpty()) {
            return xRealIp;
        }
        return request.getRemoteAddr();
    }
}

// ==================== Request Logging Filter ====================

package com.example.api.filter;

import jakarta.servlet.FilterChain;
import jakarta.servlet.ServletException;
import jakarta.servlet.http.HttpServletRequest;
import jakarta.servlet.http.HttpServletResponse;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;
import org.springframework.core.annotation.Order;
import org.springframework.stereotype.Component;
import org.springframework.web.filter.OncePerRequestFilter;

import java.io.IOException;
import java.util.UUID;

@Component
@Order(1)
public class RequestLoggingFilter extends OncePerRequestFilter {

    private static final Logger logger = LoggerFactory.getLogger(RequestLoggingFilter.class);

    @Override
    protected void doFilterInternal(HttpServletRequest request, HttpServletResponse response, FilterChain filterChain)
            throws ServletException, IOException {

        String requestId = UUID.randomUUID().toString().substring(0, 8);
        MDC.put("requestId", requestId);

        long startTime = System.currentTimeMillis();

        String clientIp = getClientIp(request);
        String method = request.getMethod();
        String uri = request.getRequestURI();
        String queryString = request.getQueryString();
        String userAgent = request.getHeader("User-Agent");
        String contentType = request.getContentType();

        logger.info("Incoming request: requestId={}, method={}, uri={}, query={}, IP={}, User-Agent='{}', Content-Type='{}'",
                requestId, method, uri, queryString, clientIp, userAgent, contentType);

        try {
            filterChain.doFilter(request, response);
        } finally {
            long duration = System.currentTimeMillis() - startTime;
            int status = response.getStatus();

            if (status >= 500) {
                logger.error("Request completed: requestId={}, method={}, uri={}, status={}, duration={}ms, IP={}",
                        requestId, method, uri, status, duration, clientIp);
            } else if (status >= 400) {
                logger.warn("Request completed: requestId={}, method={}, uri={}, status={}, duration={}ms, IP={}",
                        requestId, method, uri, status, duration, clientIp);
            } else {
                logger.info("Request completed: requestId={}, method={}, uri={}, status={}, duration={}ms, IP={}",
                        requestId, method, uri, status, duration, clientIp);
            }

            MDC.remove("requestId");
        }
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        String xRealIp = request.getHeader("X-Real-IP");
        if (xRealIp != null && !xRealIp.isEmpty()) {
            return xRealIp;
        }
        return request.getRemoteAddr();
    }
}

// ==================== Security Logging Configuration ====================

package com.example.api.config;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;

@Configuration
@EnableWebSecurity
public class SecurityConfig {

    private static final Logger logger = LoggerFactory.getLogger(SecurityConfig.class);

    @Bean
    public SecurityFilterChain securityFilterChain(HttpSecurity http) throws Exception {
        logger.info("Configuring security filter chain");

        http
            .csrf(csrf -> csrf.disable())
            .authorizeHttpRequests(auth -> auth
                .requestMatchers("/api/**").permitAll()
                .anyRequest().authenticated()
            );

        logger.info("Security filter chain configured successfully");
        return http.build();
    }
}

